AND ( user_code LIKE CONCAT('%', #{keyword,jdbcType=VARCHAR}, '%') OR endpoint LIKE CONCAT('%', #{keyword,jdbcType=VARCHAR}, '%') OR chat_id LIKE CONCAT('%', #{keyword,jdbcType=VARCHAR}, '%') OR CAST(resource_id AS VARCHAR) LIKE CONCAT('%', #{keyword,jdbcType=VARCHAR}, '%') )
